import{_ as e,c as a,o as r,d as t}from"./app.65b10671.js";const B='{"title":"\u041D\u0430\u0437\u0432\u0430\u043D\u0438\u0435","description":"","frontmatter":{"title":"\u041D\u0430\u0437\u0432\u0430\u043D\u0438\u0435","subtitle":"\u0422\u0435\u043A\u0441\u0442\u043E\u0432\u0430\u044F \u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u043A\u0430 \u0438\u0434\u0435\u0438","icon":"name.svg","date":"2020-11-01T00:00:00.000Z","color":"#EBDC61"},"headers":[{"level":3,"title":"\u041B\u0435\u0432\u043E\u0435 \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u0435 \u043C\u043E\u0437\u0433\u0430","slug":"\u043B\u0435\u0432\u043E\u0435-\u043F\u043En\u0443\u0448\u0430\u0440\u0438\u0435-\u043C\u043E\u0437\u0433\u0430"}],"relativePath":"theory/system/projectapp/twelve/02.name/index.md"}',n={},i=t('<p>\u0418\u0434\u0435\u044F \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u043E\u0431\u0440\u0430\u0437 \u0438 \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u0447\u0435\u0442\u043A\u043E\u0433\u043E \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F. \u041D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u0438\u0445 \u0441\u043B\u043E\u0432 \u0445\u0432\u0430\u0442\u0438\u0442, \u0447\u0442\u043E\u0431\u044B \u0443\u0445\u0432\u0430\u0442\u0438\u0442\u044C\u0441\u044F \u0438 \u0441\u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043D\u0430 \u043D\u0435\u0439. \u0422\u0435\u043F\u0435\u0440\u044C \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u0443\u0434\u0435\u043B\u044F\u0442\u044C \u0435\u0439 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u043D\u0435\u0435 \u0440\u0430\u0441\u043A\u0440\u044B\u0442\u044C \u0435\u0451 \u0434\u043B\u044F \u0441\u0435\u0431\u044F.</p><p>\u041D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0435\u043A\u0442\u0430 \u0441\u0442\u043E\u0438\u0442 \u0437\u0430\u043F\u0438\u0441\u0430\u0442\u044C \u0442\u0435\u043A\u0441\u0442\u043E\u043C \u0438 \u0432\u044B\u0434\u0435\u043B\u0438\u0442\u044C \u043A\u0430\u043A\u0438\u043C-\u0442\u043E \u043E\u0441\u043E\u0431\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C. \u0417\u0430\u0444\u0438\u043A\u0441\u0438\u0440\u0443\u0439\u0442\u0435 \u0435\u0433\u043E \u0432 \u0444\u043E\u0440\u043C\u0435 2-7 \u0441\u043B\u043E\u0432, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432 \u0446\u0435\u043B\u043E\u043C \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442 \u0437\u0430\u0434\u0443\u043C\u0430\u043D\u043D\u044B\u0435 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u044B \u043F\u0440\u043E\u0435\u043A\u0442\u0430.</p><p>\u041D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 \u043A\u0440\u0430\u0442\u043A\u043E \u0441\u043E\u043E\u0431\u0449\u0430\u0435\u0442 \u043E \u0442\u043E\u043C, \u0447\u0442\u043E \u043C\u044B \u0432\u043E\u043F\u043B\u043E\u0449\u0430\u0435\u043C \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0432 \u0432\u0430\u0448\u0435\u043C \u043F\u0440\u043E\u0435\u043A\u0442\u0435. \u041E\u043D\u043E \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430 \u0438\u0434\u0435\u044E, \u0430 \u043D\u0435 \u043F\u044B\u0442\u0430\u0435\u0442\u0441\u044F \u0435\u0451 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u043F\u0438\u0441\u0430\u0442\u044C. \u0417\u0430\u0444\u0438\u043A\u0441\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u0438\u0434\u0435\u044F \u2013 \u0441\u043F\u043E\u0441\u043E\u0431 \u0434\u0430\u0442\u044C \u043B\u0435\u0432\u043E\u043C\u0443 \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u044E \u043C\u043E\u0437\u0433\u0430 \u044F\u0437\u044B\u043A\u043E\u0432\u043E\u0439 \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C \u043D\u0430 \u043C\u044B\u0441\u043B\u044C, \u043A \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0431\u0443\u0434\u0435\u0442 \u0432\u043E\u0437\u0432\u0440\u0430\u0449\u0430\u0442\u044C\u0441\u044F \u0432\u043D\u043E\u0432\u044C \u0438 \u0432\u043D\u043E\u0432\u044C \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0435\u0451 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438.</p><h3 id="\u043B\u0435\u0432\u043E\u0435-\u043F\u043En\u0443\u0448\u0430\u0440\u0438\u0435-\u043C\u043E\u0437\u0433\u0430" tabindex="-1">\u041B\u0435\u0432\u043E\u0435 \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u0435 \u043C\u043E\u0437\u0433\u0430 <a class="header-anchor" href="#\u043B\u0435\u0432\u043E\u0435-\u043F\u043En\u0443\u0448\u0430\u0440\u0438\u0435-\u043C\u043E\u0437\u0433\u0430" aria-hidden="true">#</a></h3><p>\u0427\u0442\u043E\u0431\u044B \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u043D\u0430\u0448\u0435 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435, \u043C\u044B \u0441\u043E\u0437\u0434\u0430\u0435\u043C \u0434\u0432\u0430 \u0432\u0438\u0434\u0430 \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u0435\u0439 \u043D\u0430 \u043E\u0434\u043D\u0443 \u0438 \u0442\u0443 \u0436\u0435 \u043C\u044B\u0441\u043B\u044C. \u0427\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u043C\u0443 \u043C\u043E\u0437\u0433\u0443 \u0441\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u0430 <a href="https://ru.wikipedia.org/wiki/%D0%9C%D0%B5%D0%B6%D0%BF%D0%BE%D0%BB%D1%83%D1%88%D0%B0%D1%80%D0%BD%D0%B0%D1%8F_%D0%B0%D1%81%D0%B8%D0%BC%D0%BC%D0%B5%D1%82%D1%80%D0%B8%D1%8F" class="external-link" target="_blank" rel="noopener noreferrer">\u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u0430\u044F \u043C\u0435\u0436\u043F\u043E\u043B\u0443\u0448\u0430\u0440\u043D\u0430\u044F \u0430\u0441\u0438\u043C\u043C\u0435\u0442\u0440\u0438\u044F</a> \u0438 \u044F\u0437\u044B\u043A\u043E\u0432\u043E\u0435 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0441\u043B\u0443\u0436\u0438\u0442 \u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u043C \u0434\u043B\u044F \u0431\u043E\u043B\u0435\u0435 \u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0438 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u043B\u0435\u0432\u043E\u0433\u043E \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u044F.</p><p><a href="https://ru.wikipedia.org/wiki/%D0%A1%D1%82%D0%B5%D1%80%D0%B5%D0%BE%D1%81%D1%83%D0%B3%D0%B3%D0%B5%D1%81%D1%82%D0%B8%D1%8F" class="external-link" target="_blank" rel="noopener noreferrer">\u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0438 \u0412. \u0421. \u0420\u043E\u0442\u0435\u043D\u0431\u0435\u0440\u0433\u0430</a>, \xAB\u043B\u0435\u0432\u043E\u0435 \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u0435 \u0438\u0437 \u0432\u0441\u0435\u0433\u043E \u043E\u0431\u0438\u043B\u0438\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u0445 \u0438 \u043F\u043E\u0442\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0445 \u0441\u0432\u044F\u0437\u0435\u0439 \u0432\u044B\u0431\u0438\u0440\u0430\u0435\u0442 \u043D\u0435\u043C\u043D\u043E\u0433\u0438\u0435 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435 \u043D\u0435\u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0440\u0435\u0447\u0438\u0432\u044B\u0435, \u043D\u0435 \u0438\u0441\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0438\u0435 \u0434\u0440\u0443\u0433 \u0434\u0440\u0443\u0433\u0430, \u0438 \u043D\u0430 \u043E\u0441\u043D\u043E\u0432\u0435 \u044D\u0442\u0438\u0445 \u043D\u0435\u043C\u043D\u043E\u0433\u0438\u0445 \u0441\u0432\u044F\u0437\u0435\u0439 (\u0432 \u0438\u0434\u0435\u0430\u043B\u0435 \u2014 \u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u043A \u043E\u0434\u043D\u043E\u0439, \u043D\u043E \u043E\u0447\u0435\u043D\u044C \u0441\u0438\u043B\u044C\u043D\u043E\u0439) \u0441\u043E\u0437\u0434\u0430\u0435\u0442 \u043E\u0434\u043D\u043E\u0437\u043D\u0430\u0447\u043D\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0439 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442. \u0412 \u043E\u0441\u043D\u043E\u0432\u0435 \u044D\u0442\u043E\u0433\u043E \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0430 \u043B\u0435\u0436\u0438\u0442 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0435 \u043E\u0434\u043D\u043E\u0437\u043D\u0430\u0447\u043D\u044B\u0445 \u043F\u0440\u0438\u0447\u0438\u043D\u043D\u043E-\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0439 \u043C\u0435\u0436\u0434\u0443 \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u0430\u043C\u0438 \u0438 \u044F\u0432\u043B\u0435\u043D\u0438\u044F\u043C\u0438. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043E\u0434\u043D\u043E\u0437\u043D\u0430\u0447\u043D\u043E\u043C\u0443 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0443 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u043F\u043E\u043B\u043D\u043E\u0435 \u0432\u0437\u0430\u0438\u043C\u043E\u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043C\u0435\u0436\u0434\u0443 \u043B\u044E\u0434\u044C\u043C\u0438 \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0438\u0445 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438. \u041E\u0434\u043D\u043E\u0437\u043D\u0430\u0447\u043D\u043E\u0441\u0442\u044C \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0438\u0432\u0430\u0435\u0442 \u0442\u0430\u043A\u0436\u0435 \u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0430\u043D\u0430\u043B\u0438\u0437 \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u043E\u0432 \u0438 \u044F\u0432\u043B\u0435\u043D\u0438\u0439, \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u043F\u0435\u0440\u0435\u0445\u043E\u0434\u0430 \u043E\u0442 \u043E\u0434\u043D\u043E\u0433\u043E \u0443\u0440\u043E\u0432\u043D\u044F \u0440\u0430\u0441\u0441\u043C\u043E\u0442\u0440\u0435\u043D\u0438\u044F \u043A \u0434\u0440\u0443\u0433\u043E\u043C\u0443. \u041F\u0440\u0438 \u044D\u0442\u043E\u043C \u0432\u0441\u0435 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u0441\u0432\u044F\u0437\u0438, \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u044B\u0435 \u0443\u0441\u043B\u043E\u0436\u043D\u0438\u0442\u044C \u0438 \u0437\u0430\u043F\u0443\u0442\u0430\u0442\u044C \u043A\u0430\u0440\u0442\u0438\u043D\u0443, \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0435\u0451 \u043C\u0435\u043D\u0435\u0435 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435 \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0440\u0435\u0447\u0438\u0432\u043E\u0439 \u2014 \u0432\u0441\u0435 \u044D\u0442\u0438 \u0441\u0432\u044F\u0437\u0438 \u0431\u0435\u0437\u0436\u0430\u043B\u043E\u0441\u0442\u043D\u043E \u043E\u0442\u0441\u0435\u043A\u0430\u044E\u0442\u0441\u044F. \u0422\u0430\u043A\u0430\u044F \u0430\u043A\u043A\u0443\u0440\u0430\u0442\u043D\u043E \u043F\u043E\u0434\u0441\u0442\u0440\u0438\u0436\u0435\u043D\u043D\u0430\u044F \u043F\u043E\u0434 \u043C\u0430\u0448\u0438\u043D\u043A\u0443 \u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u044F \u043A\u0430\u0440\u0442\u0438\u043D\u0430 \u043C\u0438\u0440\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0443\u0436\u0435 \u043D\u0435 \u043A\u0430\u0440\u0442\u0438\u043D\u043E\u0439 \u0432 \u043F\u043E\u043B\u043D\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435 \u044D\u0442\u043E\u0433\u043E \u0441\u043B\u043E\u0432\u0430, \u0430 \u043C\u043E\u0434\u0435\u043B\u044C\u044E, \u0443\u0434\u043E\u0431\u043D\u043E\u0439 \u0432 \u043E\u0431\u0440\u0430\u0449\u0435\u043D\u0438\u0438. \u0412\u0441\u0435 \u0448\u043A\u043E\u043B\u044C\u043D\u043E\u0435 \u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0438\u0435 \u0432 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445 \u0437\u0430\u043F\u0430\u0434\u043D\u043E\u0439 \u0446\u0438\u0432\u0438\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043E \u043D\u0430 \u0441\u043A\u043E\u0440\u0435\u0439\u0448\u0435\u0435 \u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0443 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u043E\u0434\u043D\u043E\u0437\u043D\u0430\u0447\u043D\u043E\u0433\u043E \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0430 \u043B\u0435\u0432\u043E\u043F\u043E\u043B\u0443\u0448\u0430\u0440\u043D\u043E\u0433\u043E \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u044F.</p><h4 id="\u0440\u0435\u0447\u044C" tabindex="-1">\u0420\u0435\u0447\u044C <a class="header-anchor" href="#\u0440\u0435\u0447\u044C" aria-hidden="true">#</a></h4><p><strong>\u041E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0430 \u0432\u0435\u0440\u0431\u0430\u043B\u044C\u043D\u043E\u0439 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438:</strong> \u041B\u0435\u0432\u043E\u0435 \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u0435 \u043C\u043E\u0437\u0433\u0430 \u043E\u0442\u0432\u0435\u0447\u0430\u0435\u0442 \u0437\u0430 \u0432\u0430\u0448\u0438 \u044F\u0437\u044B\u043A\u043E\u0432\u044B\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u0438. \u042D\u0442\u043E \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u0435 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u0435\u0442 \u0440\u0435\u0447\u044C, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u0438 \u043A \u0447\u0442\u0435\u043D\u0438\u044E \u0438 \u043F\u0438\u0441\u044C\u043C\u0443. \u041E\u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u0437\u0430\u043F\u043E\u043C\u0438\u043D\u0430\u0435\u0442 \u0444\u0430\u043A\u0442\u044B, \u0438\u043C\u0435\u043D\u0430, \u0434\u0430\u0442\u044B \u0438 \u0438\u0445 \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u0438\u0435.</p><p>\u0424\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u044B \u043B\u0435\u043A\u0441\u0438\u043A\u043E\u043D\u0430 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0437\u0430 \u0441\u0447\u0435\u0442 \u0441\u0443\u043C\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0440\u0430\u0437\u043D\u044B\u0445 \u0441\u043B\u043E\u0435\u0432 \u043B\u0435\u043A\u0441\u0438\u043A\u0438: \u043B\u0435\u0432\u043E\u0435 \u2014 \u043D\u0430 \u0442\u043E\u0447\u043D\u044B\u0435, \u0434\u043E\u0441\u043B\u043E\u0432\u043D\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0435 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F, \xAB\u0441\u043B\u043E\u0432\u0430-\u043A\u043E\u043D\u0446\u0435\u043F\u0442\u044B\xBB.</p><p>\u041B\u0435\u0432\u043E\u0435 \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u0435 \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0438\u0432\u0430\u0435\u0442 \u0442\u0435\u043E\u0440\u0435\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435, \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043E\u0444\u043E\u0440\u043C\u043B\u0435\u043D\u0438\u0435 \u0432\u044B\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u043D\u0438\u044F \u0438 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0443 \u0441\u0432\u043E\u0439\u0441\u0442\u0432 \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u043E\u0432;</p><h4 id="\u043C\u044B\u0448n\u0435\u043D\u0438\u0435" tabindex="-1">\u041C\u044B\u0448\u043B\u0435\u043D\u0438\u0435 <a class="header-anchor" href="#\u043C\u044B\u0448n\u0435\u043D\u0438\u0435" aria-hidden="true">#</a></h4><p><strong>\u0410\u043D\u0430\u043B\u0438\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435:</strong> \u041B\u0435\u0432\u043E\u0435 \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u0435 \u043E\u0442\u0432\u0435\u0447\u0430\u0435\u0442 \u0437\u0430 \u043B\u043E\u0433\u0438\u043A\u0443 \u0438 \u0430\u043D\u0430\u043B\u0438\u0437. \u0418\u043C\u0435\u043D\u043D\u043E \u043E\u043D\u043E \u0430\u043D\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u0435\u0442 \u0432\u0441\u0435 \u0444\u0430\u043A\u0442\u044B. \u0427\u0438\u0441\u043B\u0430 \u0438 \u043C\u0430\u0442\u0435\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0441\u0438\u043C\u0432\u043E\u043B\u044B \u0442\u0430\u043A\u0436\u0435 \u0440\u0430\u0441\u043F\u043E\u0437\u043D\u0430\u044E\u0442\u0441\u044F \u043B\u0435\u0432\u044B\u043C \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u0435\u043C.</p><p><strong>\u041F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0430 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438:</strong> \u0418\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044F \u043E\u0431\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043B\u0435\u0432\u044B\u043C \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u0435\u043C \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u043E \u044D\u0442\u0430\u043F\u0430\u043C.</p><p>\u0421\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u043A \u0440\u0435\u0447\u0438, \u0430\u043D\u0430\u043B\u0438\u0437\u0443, \u0434\u0435\u0442\u0430\u043B\u0438\u0437\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044E, \u0430\u0431\u0441\u0442\u0440\u0430\u043A\u0446\u0438\u0438 \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043B\u0435\u0432\u044B\u043C \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u0435\u043C \u043C\u043E\u0437\u0433\u0430. \u041E\u043D\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0432\u044B\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u044F \u0446\u0435\u043F\u043E\u0447\u043A\u0438, \u0430\u043B\u0433\u043E\u0440\u0438\u0442\u043C\u044B, \u043E\u043F\u0435\u0440\u0438\u0440\u0443\u044F \u0444\u0430\u043A\u0442\u043E\u043C, \u0434\u0435\u0442\u0430\u043B\u044C\u044E, \u0441\u0438\u043C\u0432\u043E\u043B\u043E\u043C, \u0437\u043D\u0430\u043A\u043E\u043C, \u043E\u0442\u0432\u0435\u0447\u0430\u0435\u0442 \u0437\u0430 \u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442 \u0432 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0438.</p><h4 id="\u0446\u0432\u0435\u0442\u0430" tabindex="-1">\u0426\u0432\u0435\u0442\u0430 <a class="header-anchor" href="#\u0446\u0432\u0435\u0442\u0430" aria-hidden="true">#</a></h4><p>\u041B\u0435\u0432\u043E\u0435 \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u0435 \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0438\u0432\u0430\u0435\u0442 \u0441\u043B\u043E\u0432\u0435\u0441\u043D\u043E\u0435 \u043A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0446\u0432\u0435\u0442\u043E\u0432 \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0440\u0435\u0434\u043A\u0438\u0445 \u0432 \u044F\u0437\u044B\u043A\u0435, \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0445 \u0438 \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u043D\u043E \u0441\u043E\u043E\u0442\u043D\u0435\u0441\u0435\u043D\u043D\u044B\u0445 \u043D\u0430\u0437\u0432\u0430\u043D\u0438\u0439. \u041F\u0440\u0438 \u0443\u0433\u043D\u0435\u0442\u0435\u043D\u0438\u0438 \u043B\u0435\u0432\u043E\u0433\u043E \u043F\u043E\u043B\u0443\u0448\u0430\u0440\u0438\u044F \u0438\u0437 \u043B\u0435\u043A\u0441\u0438\u043A\u043E\u043D\u0430 \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0442 \u0442\u0430\u043A\u0438\u0435 \u043D\u0430\u0437\u0432\u0430\u043D\u0438\u044F \u0446\u0432\u0435\u0442\u043E\u0432, \u043A\u0430\u043A \u043E\u0440\u0430\u043D\u0436\u0435\u0432\u044B\u0439, \u0442\u0435\u0440\u0440\u0430\u043A\u043E\u0442\u043E\u0432\u044B\u0439, \u0432\u0438\u0448\u043D\u0435\u0432\u044B\u0439, \u0446\u0432\u0435\u0442 \u043C\u043E\u0440\u0441\u043A\u043E\u0439 \u0432\u043E\u043B\u043D\u044B \u0438 \u0442. \u043F.</p>',16),o=[i];function s(p,D,d,h,c,l){return r(),a("div",null,o)}var f=e(n,[["render",s]]);export{B as __pageData,f as default};
